			Hello,
<br/>I want to detect the existence of a microphone and its details before recording.
<br/>I coded the function below. The problem is, I can't get the device name (e.g., cde linux arecord -l result=&quot;card 1: UM1 [WOODBRASS UM1], device 0: USB Audio [USB Audio]&quot;).
<br/>one solution ?
<br/>thanks.
<br/><br/>ma fonction:
<br/><i>//Ctrl existance input MIC
<br/>function MIC_lireinfo(var vMicDeviceName,vMicHostAPIName:string;var vmes:string):boolean;
<br/>var VuosDefaultDeviceIn:cint32;
<br/>&nbsp; &nbsp; VTuos_DeviceInfos:Tuos_DeviceInfos; &nbsp;
<br/>&nbsp; &nbsp; devinf: PPaDeviceInfo;
<br/>&nbsp; &nbsp; apiinf: PPaHostApiInfo;
<br/>begin
<br/>result:=false;vmes:='';
<br/>VuosDefaultDeviceIn:=Pa_GetDefaultInPutDevice ();
<br/>&nbsp; &nbsp; if VuosDefaultDeviceIn=-1
<br/>&nbsp; &nbsp; then vmes:='MIC: pas de micro'
<br/>&nbsp; &nbsp; else begin
<br/>&nbsp; &nbsp; result:=true;
<br/>&nbsp; &nbsp; VTuos_DeviceInfos.DeviceNum :=VuosDefaultDeviceIn;//x;
<br/><br/>&nbsp; &nbsp; devinf := Pa_GetDeviceInfo (VuosDefaultDeviceIn);//x);
<br/>&nbsp; &nbsp; apiinf := Pa_GetHostApiInfo (devinf^.hostApi);
<br/><br/>&nbsp; &nbsp; VTuos_DeviceInfos.DeviceName := UTF8Decode (devinf^._name);
<br/>&nbsp; &nbsp; VTuos_DeviceInfos.HostAPIName := UTF8Decode (apiinf^._name);
<br/><br/>&nbsp; &nbsp; vMicDeviceName:=VTuos_DeviceInfos.DeviceName;
<br/>&nbsp; &nbsp; vMicHostAPIName:=VTuos_DeviceInfos.HostAPIName ;
<br/>&nbsp; &nbsp; end;
<br/>end; &nbsp; </i><br/><br/>Resultat &quot;apiinf^&quot;:
<br/><i>record PAHOSTAPIINFO {
<br/>&nbsp; STRUCTVERSION = 1, 
<br/>&nbsp; _TYPE = PAALSA, 
<br/>&nbsp; _NAME = 'ALSA', 
<br/>&nbsp; DEVICECOUNT = 11, 
<br/>&nbsp; DEFAULTINPUTDEVICE = 10, 
<br/>&nbsp; DEFAULTOUTPUTDEVICE = 10}</i><br/><br/>Resultat &quot;devinf^&quot;:
<br/><i>record PADEVICEINFO {
<br/>&nbsp; STRUCTVERSION = 2, 
<br/>&nbsp; _NAME = 'default', 
<br/>&nbsp; HOSTAPI = 0, 
<br/>&nbsp; MAXINPUTCHANNELS = 32, 
<br/>&nbsp; MAXOUTPUTCHANNELS = 32, 
<br/>&nbsp; DEFAULTLOWINPUTLATENCY = 0.0086848072562358269, 
<br/>&nbsp; DEFAULTLOWOUTPUTLATENCY = 0.0086848072562358269, 
<br/>&nbsp; DEFAULTHIGHINPUTLATENCY = 0.034807256235827665, 
<br/>&nbsp; DEFAULTHIGHOUTPUTLATENCY = 0.034807256235827665, 
<br/>&nbsp; DEFAULTSAMPLERATE = 44100}</i><br/>

			@edf 
<br/>i have found another way to fix the clipping of 2 inputs 
<br/>I had to set 
<br/>sampleformat:=0; // 0: Float32
<br/>and not to default value 
<br/>sampleformat:=-1; //2:Int16
<br/><br/><br/>***********************
<br/>procedure TForm1.ButtonRecordSpeakersClick(Sender: TObject);
<br/>var
<br/>&nbsp; outformatst: string;
<br/>&nbsp; sampleformat,outformat, numchan: integer;
<br/>begin
<br/><br/>&nbsp; &nbsp; PlayerIndex1 := 0;
<br/>&nbsp; &nbsp; // PlayerIndex : from 0 to what your computer can do ! (depends of ram, cpu, ...)
<br/>&nbsp; &nbsp; // If PlayerIndex exists already, it will be overwritten...
<br/><br/>&nbsp; &nbsp; uos_CreatePlayer(PlayerIndex1);
<br/><br/>&nbsp; &nbsp; sampleformat:=0; //0works ! 1 does not work ! &nbsp;2 does not work!
<br/><br/><br/>&nbsp; &nbsp; if RadioButtonWav.Checked then
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; outformatst := '.wav';
<br/>&nbsp; &nbsp; &nbsp; outformat := 0;
<br/>&nbsp; &nbsp; end
<br/>&nbsp; &nbsp; else
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; outformatst := '.ogg';
<br/>&nbsp; &nbsp; &nbsp; outformat := 3;
<br/>&nbsp; &nbsp; end;
<br/><br/>&nbsp; &nbsp; EditSpeakersPath.Text := 'rec_' + UTF8Decode(formatdatetime('YY_MM_DD_HH_mm_ss', now)) + outformatst;
<br/><br/><br/>&nbsp; &nbsp; //In1Index1 := uos_AddFromDevIn(PlayerIndex1,-1,0.8,44100,-1,0,-1,-1); //-1 is speaker - 18 pulse works
<br/>&nbsp; &nbsp; In1Index1 := uos_AddFromDevIn(PlayerIndex1, &nbsp;-1, -1 ,-1 &nbsp; ,-1,sampleformat,1024,-1); //-1 is speaker - 18 pulse works
<br/>&nbsp; &nbsp; numchan := uos_InputGetChannels(PlayerIndex1, In1Index1);
<br/>&nbsp; &nbsp; LabelSpeakersChannel.Caption:=inttostr(numchan);
<br/><br/>&nbsp; &nbsp; In1Index2 := uos_AddFromDevIn(PlayerIndex2, &nbsp;0, -1 , &nbsp;-1 &nbsp; ,-1,sampleformat,1024,-1); //0 is mic - 18 pulse works
<br/>&nbsp; &nbsp; numchan := uos_InputGetChannels(PlayerIndex2, In1Index2);
<br/>&nbsp; &nbsp; LabelMicChannel.Caption:=inttostr(numchan);
<br/><br/>&nbsp; &nbsp; //mut := uos_AddFromEndlessMuted(PlayerIndex1,2,1024);
<br/>&nbsp; &nbsp; //uos_InputSetEnable(PlayerIndex1, mut, True);
<br/><br/><br/>&nbsp; &nbsp; uos_AddIntoFile(PlayerIndex1, PChar(EditSpeakersPath.Text), -1, 2,sampleformat,1024, outformat); //-1
<br/><br/><br/><br/>&nbsp; &nbsp; uos_InputAddDSPVolume(PlayerIndex1, In1Index1, 1, 1);
<br/>&nbsp; &nbsp; uos_InputAddDSPVolume(PlayerIndex1, In1Index2, 1, 1);
<br/><br/>&nbsp; &nbsp; //uos_InputSetDSPVolume(PlayerIndex1, In1Index1, TrackBar1.position / 100, TrackBar3.position / 100, True); // Set volume
<br/><br/><br/><br/>&nbsp; &nbsp; uos_Play(PlayerIndex1); &nbsp;// everything is ready to play...
<br/><br/>&nbsp; &nbsp; ButtonRecordSpeakers.Enabled := False;
<br/>&nbsp; &nbsp; ButtonStopRecordSpeakers.Enabled := True;
<br/><br/><br/>end;

			&gt; &nbsp; &nbsp;In1Index1 := uos_AddFromDevIn(PlayerIndex1, &nbsp;-1,0.02,-1 &nbsp; ,-1,2,1024,-1); //-1 is speaker - 18 pulse works
<br/>&gt; &nbsp; &nbsp;numchan := uos_InputGetChannels(PlayerIndex1, In1Index1);
<br/>&gt; &nbsp; &nbsp;label3.Caption:=inttostr(numchan);
<br/><br/>&gt; &nbsp; &nbsp;In1Index2 := uos_AddFromDevIn(PlayerIndex1, &nbsp;0,0.02, -1, &nbsp; -1,2,1024,-1); //0 is mic
<br/>&gt; &nbsp; &nbsp;numchan := uos_InputGetChannels(PlayerIndex1, In1Index2);
<br/>&nbsp;&gt; &nbsp; label8.Caption:=inttostr(numchan);
<br/><br/><br/>Hum, the second uos_AddFromDevIn seems strange and the first should target a input device.
<br/>There is a demo devicesinfos to see what input device you have.
<br/><br/>So it should be something like:
<br/><br/>&nbsp; &nbsp; In1Index1 := uos_AddFromDevIn(PlayerIndex1, &nbsp;-1,0.02,-1 &nbsp; ,-1,2,1024,-1); //-1 should be the default device in
<br/>&nbsp; &nbsp; numchan := uos_InputGetChannels(PlayerIndex1, In1Index1);
<br/>&nbsp; &nbsp; label3.Caption:=inttostr(numchan);
<br/><br/>&nbsp; &nbsp; In1Index2 := uos_AddFromDevIn(PlayerIndex1, &nbsp;deivicein2, 0.02,-1 &nbsp; ,-1,2,1024,-1); //devicein2 &nbsp;should be the default device in of second card.
<br/>&nbsp; &nbsp; numchan := uos_InputGetChannels(PlayerIndex1, In1Index2);
<br/>&nbsp; &nbsp;label8.Caption:=inttostr(numchan);
<br/>

