<br/><br/>procedure Tmainvosk3_for.LoopProcPlayer1;
<br/>var
<br/>aBufLen: integer;
<br/>FBufRcFromUos: TDArFloat; // Mon buffer
<br/>Vfinal:cardinal;
<br/>LBuffer:TBytes;//TSingleArrayDyn;
<br/>i,j:integer;
<br/>VtbytesTmp:tbytes;
<br/>Vsingle:cfloat;//single;
<br/>vind:integer;
<br/>begin
<br/>&nbsp; &nbsp; &nbsp;try
<br/>// &nbsp;ShowPosition;
<br/>// &nbsp;ShowLevel;
<br/>&nbsp; FBufRcFromUos:=uos_InputGetBuffer(PlayerIndex1, In1Index);
<br/>&nbsp; aBufLen:=Length(FBufRcFromUos);
<br/><br/>&nbsp; &nbsp; //Traiter LBuffer
<br/>&nbsp; &nbsp; &nbsp; if FTVoskRecognizer=nil
<br/>&nbsp; &nbsp; &nbsp; then for_message('FTVoskRecognizer=nil')
<br/>&nbsp; &nbsp; &nbsp; else begin
<br/>&nbsp; &nbsp; &nbsp; <b>Vfinal := FTVoskRecognizer.AcceptWaveform(Psingle(FBufRcFromUos),abuflen);</b><br/><br/>&nbsp; &nbsp; &nbsp; // @returns 1 if silence is occured and you can retrieve a new utterance with result method
<br/>&nbsp; &nbsp; &nbsp; // &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 0 if decoding continues
<br/>&nbsp; &nbsp; &nbsp; // &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; -1 if exception occured *)
<br/>&nbsp; &nbsp; &nbsp; &nbsp; case Vfinal of
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;1 &nbsp; &nbsp; &nbsp;:for_message(FTVoskRecognizer.GetResult);
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;0 &nbsp; &nbsp; &nbsp;:for_message(FTVoskRecognizer.GetPartialResult);
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;-1 &nbsp; &nbsp; :for_message('exception vosk_recognizer_accept_waveform');
<br/>&nbsp; &nbsp; &nbsp; &nbsp; end;
<br/>&nbsp; &nbsp; &nbsp; end;
<br/><br/>&nbsp; &nbsp; end;
<br/>&nbsp; &nbsp; except
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; on E:Exception do
