<br/><br/><br/>PS : One important downside of the OPUS is the fact that works only at 48000 samplerate .
<br/>&nbsp;I have tried to move from OGG to opus for the recording part but works at 48000 and my card has 44100 so plays accelerated the recording . 
<br/><br/>//modded to record opus
<br/>function Tuos_Player.AddIntoFile (Filenamepath: PChar; SampleRate: CDouble;
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Channels: cint32; SampleFormat: cint32; FramesCount: cint32;
<br/>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;FileFormat: cint32): cint32;
<br/>// Add an Output into audio wav file with custom parameters
<br/>// FileName : filename of saved audio wav file
<br/>// SampleRate : default: -1 (44100)
<br/>// Channels : default: -1 (2:stereo) (0: no channels, 1:mono, 2:stereo, ...)
<br/>// SampleFormat : default: -1 (2:Int16) ( 1:Int32, 2:Int16)
<br/>// FramesCount : default: -1 (= 4096)
<br/>// FileFormat : default: -1 (wav) (0:wav, 1:pcm, 2:custom, 3:ogg, 4:opus);
<br/>// &nbsp;result : Output Index in array &nbsp;-1 = error
<br/>// example : OutputIndex1 := AddIntoFile (edit5.Text,-1,-1, 0, -1, -1);
<br/>var 
<br/>&nbsp; x: cint32;
<br/>&nbsp; wChunkSize: cint32;
<br/>&nbsp; wFileSize: cint32;
<br/>&nbsp; IDwav: array[0..3] of char;
<br/>&nbsp; Header: Tuos_WaveHeaderChunk;
<br/>&nbsp; {$IF DEFINED (sndfile)}
<br/>&nbsp; sfInfo: TSF_INFO;
<br/>&nbsp; {$endif}
<br/><br/>begin
<br/>&nbsp; result := -1;
<br/>&nbsp; x := 0;
<br/>&nbsp; SetLength (StreamOut, Length (StreamOut) + 1);
<br/>&nbsp; StreamOut[Length (StreamOut) - 1] := Tuos_OutStream.Create ();
<br/>&nbsp; x := Length (StreamOut) - 1;
<br/>&nbsp; StreamOut[x].Data.Enabled := false;
<br/>&nbsp; StreamOut[x].FileBuffer.ERROR := 0;
<br/>&nbsp; StreamOut[x].Data.Filename := filenamepath;
<br/>&nbsp; if (FileFormat = -1) or (FileFormat = 0) then
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.FileFormat := 0
<br/>&nbsp; else StreamOut[x].FileBuffer.FileFormat := FileFormat;
<br/><br/>&nbsp; FillChar (StreamOut[x].FileBuffer, sizeof (StreamOut[x].FileBuffer), 0);
<br/><br/>&nbsp; result := x;
<br/><br/>&nbsp; if (Channels = -1) then
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.wChannels := 2
<br/>&nbsp; else
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.wChannels := Channels;
<br/><br/>&nbsp; StreamOut[x].Data.Channels := StreamOut[x].FileBuffer.wChannels;
<br/><br/>&nbsp; if FramesCount = -1 then &nbsp;StreamOut[x].Data.Wantframes := &nbsp;65536 Div StreamOut[x].Data.Channels
<br/>&nbsp; else
<br/>&nbsp; &nbsp; StreamOut[x].Data.Wantframes := FramesCount;
<br/><br/>&nbsp; SetLength (StreamOut[x].Data.Buffer, StreamOut[x].Data.Wantframes*StreamOut[x].Data.Channels);
<br/><br/>&nbsp; if (SampleFormat = -1) or (SampleFormat = 2) then
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.wBitsPerSample := 16;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.SampleFormat := 2;
<br/>&nbsp; &nbsp; end;
<br/><br/>&nbsp; if (SampleFormat = 1) then
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.wBitsPerSample := 32;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.SampleFormat := 1;
<br/>&nbsp; &nbsp; end;
<br/><br/>&nbsp; if (SampleFormat = 0) then
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.wBitsPerSample := 32;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.SampleFormat := 0;
<br/>&nbsp; &nbsp; end;
<br/><br/>&nbsp; if SampleRate = -1 then
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.wSamplesPerSec := 44100
<br/>&nbsp; else
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.wSamplesPerSec := roundmath (samplerate);
<br/><br/>&nbsp; StreamOut[x].Data.Samplerate := StreamOut[x].FileBuffer.wSamplesPerSec;
<br/>&nbsp; StreamOut[x].LoopProc := Nil;
<br/><br/>&nbsp; if fileformat = 3 then
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; // ogg file
<br/>&nbsp; {$IF DEFINED (sndfile)}
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.FileFormat := 3;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.TypePut := 6;
<br/>&nbsp; &nbsp; &nbsp; sfInfo.format := SF_FORMAT_OGG Or SF_FORMAT_VORBIS;
<br/>&nbsp; &nbsp; &nbsp; sfInfo.channels := StreamOut[x].Data.Channels;
<br/>&nbsp; &nbsp; &nbsp; sfInfo.frames := &nbsp;streamOut[x].Data.Wantframes;
<br/>&nbsp; &nbsp; &nbsp; SFinfo.samplerate := StreamOut[x].FileBuffer.wSamplesPerSec;
<br/>&nbsp; &nbsp; &nbsp; SFinfo.seekable := 0;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.Enabled := True;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.HandleSt := sf_open (pchar (FileNamepath), SFM_WRITE, sfInfo);
<br/>&nbsp; {$endif}
<br/>&nbsp; &nbsp; end
<br/>&nbsp; else if fileformat = 4 then begin &nbsp;//by trustfm
<br/>&nbsp; &nbsp; StreamOut[x].FileBuffer.FileFormat := 3;
<br/>&nbsp; &nbsp; StreamOut[x].Data.TypePut := 6;
<br/>&nbsp; &nbsp; sfInfo.format := SF_FORMAT_OGG or SF_FORMAT_OPUS; //SF_FORMAT_OGG Or SF_FORMAT_VORBIS;
<br/><br/>&nbsp; &nbsp; sfInfo.channels := StreamOut[x].Data.Channels;
<br/>&nbsp; &nbsp; sfInfo.frames := &nbsp;streamOut[x].Data.Wantframes;
<br/>&nbsp; &nbsp; sfinfo.samplerate := 48000;// StreamOut[x].FileBuffer.wSamplesPerSec; //48000; &nbsp;OPUS WORKS AT 48000 ONLY :(
<br/>&nbsp; &nbsp; //SFinfo.samplerate := StreamOut[x].FileBuffer.wSamplesPerSec;
<br/>&nbsp; &nbsp; SFinfo.seekable := 0;
<br/>&nbsp; &nbsp; StreamOut[x].Data.Enabled := True;
<br/>&nbsp; &nbsp; StreamOut[x].Data.HandleSt := sf_open (pchar (FileNamepath), SFM_WRITE, sfInfo);
<br/>&nbsp; end
<br/>&nbsp; else
<br/>&nbsp; &nbsp; begin
<br/>&nbsp; &nbsp; &nbsp; // wav file
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data := TFileStream.Create (filenamepath,fmCreate);
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.Seek (0, soFromBeginning);
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.TypePut := 0;
<br/>&nbsp; &nbsp; &nbsp; IDwav := 'RIFF';
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (IDwav, 4);
<br/>&nbsp; &nbsp; &nbsp; wFileSize := 0;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (wFileSize, 4);
<br/>&nbsp; &nbsp; &nbsp; IDwav := 'WAVE';
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (IDwav, 4);
<br/>&nbsp; &nbsp; &nbsp; IDwav := 'fmt ';
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (IDwav, 4);
<br/>&nbsp; &nbsp; &nbsp; wChunkSize := SizeOf (Header);
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (wChunkSize, 4);
<br/><br/>&nbsp; &nbsp; &nbsp; case SampleFormat of
<br/>&nbsp; &nbsp; &nbsp; &nbsp; 0: &nbsp; Header.wFormatTag &nbsp; &nbsp; &nbsp;:= 3;
<br/>&nbsp; &nbsp; &nbsp; &nbsp; else Header.wFormatTag &nbsp; &nbsp; &nbsp;:= 1;
<br/>&nbsp; &nbsp; &nbsp; end;
<br/><br/>&nbsp; &nbsp; &nbsp; //Header.wFormatTag &nbsp; &nbsp; &nbsp;:= 1;
<br/>&nbsp; &nbsp; &nbsp; Header.wChannels &nbsp; &nbsp; &nbsp; := StreamOut[x].FileBuffer.wChannels;
<br/>&nbsp; &nbsp; &nbsp; Header.wSamplesPerSec &nbsp;:= StreamOut[x].FileBuffer.wSamplesPerSec;
<br/>&nbsp; &nbsp; &nbsp; Header.wBitsPerSample &nbsp;:= StreamOut[x].FileBuffer.wBitsPerSample;
<br/>&nbsp; &nbsp; &nbsp; Header.wBlockAlign &nbsp; &nbsp; := StreamOut[x].FileBuffer.wChannels * Header.wBitsPerSample Div 8;
<br/>&nbsp; &nbsp; &nbsp; Header.wAvgBytesPerSec := StreamOut[x].FileBuffer.wSamplesPerSec * Header.wBlockAlign;
<br/>&nbsp; &nbsp; &nbsp; Header.wcbSize &nbsp; &nbsp; &nbsp; &nbsp; := 0;
<br/><br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (Header, SizeOf (Header));
<br/>&nbsp; &nbsp; &nbsp; IDwav := 'data';
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (IDwav, 4);
<br/>&nbsp; &nbsp; &nbsp; wChunkSize := 0;
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].FileBuffer.Data.WriteBuffer (wChunkSize, 4);
<br/>&nbsp; &nbsp; &nbsp; StreamOut[x].Data.Enabled := True;
<br/><br/>&nbsp; &nbsp; end;
<br/>end; 
<br/><br/>*******************************************************
